import argparse
import json
import os
from pathlib import Path


class AttributeDict(dict):
    def __getattr__(self, name):
        return (
            self[name]
            if not isinstance(self[name], dict)
            else AttributeDict(self[name])
        )


class Settings(AttributeDict):
    # Constructor
    def __init__(self, name="Default setting", version="0.0"):
        super().__init__()
        self["name"] = name
        self["version"] = version

    def read_config_file(self, cfg_file):
        with open(cfg_file, "r", encoding="utf-8") as file_object:
            self.read_config(file_object.read())

    def read_config(self, cfg_string):
        self.update(json.loads(cfg_string))

    def build_parser(self, required_args=None):
        if required_args is None:
            required_args = ["config", "gpu"]

        parser = argparse.ArgumentParser()

        # Defining parameters
        if "config" in required_args:
            parser.add_argument(
                "--config", dest="config", help="Configuration file (.cfg)"
            )
        if "gpu" in required_args:
            parser.add_argument(
                "--gpu", dest="gpu", help="Set which GPU should be used"
            )
        if "input" in required_args:
            parser.add_argument(
                "--input", dest="input", help="Set input file to process"
            )
        if "output" in required_args:
            parser.add_argument("--output", dest="output", help="Set output folder")
        if "mode" in required_args:
            parser.add_argument(
                "--mode", dest="mode", help="Whether to test or validate"
            )

        parser.add_argument(
            "--checkpoint", dest="checkpoint", help="Configure checkpoint to load"
        )

        args = parser.parse_args()

        # Remove deprecated message from tensorflow
        os.environ["TF_CPP_MIN_LOG_LEVEL"] = "2"

        # GPU parameter
        if "gpu" in required_args and args.gpu:
            os.environ["CUDA_VISIBLE_DEVICES"] = args.gpu
        elif "gpu" in required_args:
            print(
                "Please specify --gpu to select a GPU. "
                "You can run 'gpustat' in order to see which GPU is available on the machine."
            )
            exit(0)

        # Configuration file parameter
        if "config" in required_args and args.config:
            self.read_config_file(args.config)
        elif "config" in required_args:
            print("Please specify --config to select a configuration file.")
            exit(0)

        # Input parameter
        if "input" in required_args and args.input:
            self["input"] = args.input
        elif "input" in required_args:
            print("Please specify the --input file.")
            exit(0)

        # Output parameter
        if "output" in required_args and args.output:
            self["process_folder"] = args.output
        elif "output" in required_args:
            print(
                '[INFORMATION] No output folder was specified, output folder is "./".'
            )
            self["process_folder"] = "."

            # Checkpoint parameter
            if args.checkpoint:
                self["checkpoint"] = int(args.checkpoint)
            else:
                files = [
                    str(file) for file in Path(self["outputs"]["path"]).glob("*.index")
                ]
                print(files)
                if len(files) == 0:  # No checkpoint
                    self["checkpoint"] = None
                    if "checkpoint" in required_args:
                        print(
                            "No checkpoint was found. Please verify config file, or specify using the --ckpt parameter."
                        )
                        exit(0)
                    print(
                        "[INFORMATION] No checkpoint was specified or available, starting from scratch."
                    )
                else:
                    checkpoints = []
                    for checkpoint in files:
                        checkpoint = checkpoint.replace("\\", "/")
                        checkpoint = checkpoint.replace(
                            self["outputs"]["path"] + self["outputs"]["model"] + "-", ""
                        )
                        checkpoint = checkpoint.replace(".index", "")
                        checkpoints.append(int(checkpoint))

                    self["checkpoint"] = max(checkpoints)
                    print(
                        "[INFORMATION] No checkpoint was specified, found last checkpoint: {}.".format(
                            self["checkpoint"]
                        )
                    )
